                    <button type="submit" className="btn-primary">
                      {editingProduct ? 'Update Product' : 'Add Product'}
                    </button>
                    <button 
                      type="button" 
                      className="btn-secondary"
                      onClick={() => {
                        setShowAddProduct(false);
                        setEditingProduct(null);
                        setProductForm({name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''});
                      }}
                    >
                      Cancel
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="products-grid">
              {products.map(product => (
                <div key={product.id} className="product-card">
                  <img src={product.image_url} alt={product.name} className="product-image" />
                  <div className="product-info">
                    <div className="product-name">{product.name}</div>
                    <div className="product-price">{parseFloat(product.price).toFixed(2)} ETB</div>
                    <div>Stock: {product.stock}</div>
                    <div style={{marginTop: '1rem'}}>
                      <button 
                        className="btn-primary"
                        onClick={() => editProduct(product)}
                      >
                        Edit
                      </button>
                      <button 
                        className="btn-primary" 
                        style={{background: '#dc3545', marginLeft: '0.5rem'}}
                        onClick={() => deleteProduct(product.id)}
                      >
                        Delete
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="admin-content">
            <h3>Manage Users</h3>
            <div className="users-table">
              <table>
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Email</th>
                    <th>Role</th>
                    <th>Created</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(user => (
                    <tr key={user.id}>
                      <td>{user.id}</td>
                      <td>{user.name}</td>
                      <td>{user.email}</td>
                      <td>{user.role}</td>
                      <td>{new Date(user.created_at).toLocaleDateString()}</td>
                      <td>
                        <button 
                          className="btn-danger"
                          onClick={() => deleteUser(user.id)}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="admin-content">
            <h3>Manage Orders</h3>
            <div className="orders-table">
              {orders.map(order => (
                <div key={order.id} className="order-card">
                  <div className="order-header">
                    <h4>Order #{order.id}</h4>
                    <select 
                      value={order.status}
                      onChange={(e) => updateOrderStatus(order.id, e.target.value)}
                      className="status-select"
                    >
                      <option value="pending">Pending</option>
                      <option value="shipped">Shipped</option>
                      <option value="delivered">Delivered</option>
                      <option value="cancelled">Cancelled</option>
                    </select>
                  </div>
                  <div className="order-details">
                    <p><strong>Customer:</strong> {order.customer_name} ({order.customer_email})</p>
                    <p><strong>Total:</strong> {parseFloat(order.total).toFixed(2)} ETB</p>
                    <p><strong>Payment:</strong> {order.payment_method}</p>
                    <p><strong>Items:</strong> {order.items}</p>
                    <p><strong>Address:</strong> {order.shipping_address}</p>
                    <p><strong>Date:</strong> {new Date(order.created_at).toLocaleDateString()}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'reports' && (
          <div className="admin-content">
            <h3>Sales Reports</h3>
            {salesReport && (
              <div className="sales-summary">
                <div className="summary-cards">
                  <div className="summary-card">
                    <h4>Total Orders</h4>
                    <p className="summary-number">{salesReport.summary.total_orders}</p>
                  </div>
                  <div className="summary-card">
                    <h4>Total Revenue</h4>
                    <p className="summary-number">{parseFloat(salesReport.summary.total_revenue || 0).toFixed(2)} ETB</p>
                  </div>
                </div>

                <div className="daily-report">
                  <h4>Daily Sales (Last 30 Days)</h4>
                  <table>
                    <thead>
                      <tr>
                        <th>Date</th>
                        <th>Orders</th>
                        <th>Revenue</th>
                      </tr>
                    </thead>
                    <tbody>
                      {salesReport.daily_data.map(day => (
                        <tr key={day.order_date}>
                          <td>{new Date(day.order_date).toLocaleDateString()}</td>
                          <td>{day.total_orders}</td>
                          <td>{parseFloat(day.total_revenue).toFixed(2)} ETB</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </section>
  );
};

const getCategoryIcon = (categoryName) => {
  const icons = {
    'Electronics': 'laptop',
    'Clothing': 'tshirt',
    'Home': 'home'
  };
  return icons[categoryName] || 'box';
};

export default App;
